# contrast_audit.py  —  Claude Code output
def linearize(c):
    c = c / 255.0
    return c / 12.92 if c <= 0.04045 else ((c + 0.055) / 1.055) ** 2.4

def luminance(hex_color):
    hex_color = hex_color.lstrip('#')
    r, g, b = [int(hex_color[i:i+2], 16) for i in (0,2,4)]
    return 0.2126*linearize(r) + 0.7152*linearize(g) + 0.0722*linearize(b)

def contrast_ratio(fg_hex, bg_hex):
    L1 = max(luminance(fg_hex), luminance(bg_hex))
    L2 = min(luminance(fg_hex), luminance(bg_hex))
    return (L1 + 0.05) / (L2 + 0.05)

def rating(ratio):
    if ratio >= 7.0:  return 'PASS-AAA'
    if ratio >= 4.5:  return 'PASS-AA-normal'
    if ratio >= 3.0:  return 'PASS-AA-large'
    return 'FAIL'

